            if va["acc"] > best_acc:
                best_acc = va["acc"]
                out_name = os.path.splitext(os.path.basename(ckpt_path))[0]
                best_path = os.path.join(args.out_dir, f"{out_name}_{cfg.arch}_finetuned_best.pth")
